def tonelli_shanks(n, p):

    if pow(n, (p - 1) // 2, p) != 1:
        return None

    q = p - 1
    s = 0
    while q % 2 == 0:
        q //= 2
        s += 1

    if s == 1:
        r = pow(n, (p + 1) // 4, p)
        return r, p - r

    z = 2
    while pow(z, (p - 1) // 2, p) != p - 1:
        z += 1

    c = pow(z, q, p)
    r = pow(n, (q + 1) // 2, p)
    t = pow(n, q, p)
    m = s

    while t != 1:

        i = 1
        temp = pow(t, 2, p)

        while temp != 1:
            temp = pow(temp, 2, p)
            i += 1

        b = pow(c, 2 ** (m - i - 1), p)

        r = (r * b) % p
        t = (t * b * b) % p
        c = (b * b) % p
        m = i

    root1 = r
    root2 = p - r
    print("Root1:", root1,"\n")
    print("Root2:", root2)

